router3.get("/status/:externalId", async (req, res, next) => {
  try {
    const { externalId } = req.params;
    const prisma2 = getPrismaClient();
    const user = await prisma2.user.findUnique({
      where: { externalId },
      include: {
        apiKeys: {
          where: { isActive: true },
          select: { id: true }
        }
      }
    });
    if (!user) {
      return res.json({
        externalId,
        walletAddress: null,
        hasWallet: false,
        hasApiKey: false,
        status: "NOT_FOUND",
        isReady: false,
        message: "User not found. Call POST /api/bot/setup first."
      });
    }
    const walletService = getSolanaWalletService();
    const walletInfo = await walletService.getWalletInfo(user.id);
    if (!walletInfo) {
      return res.json({
        externalId,
        walletAddress: null,
        hasWallet: false,
        hasApiKey: user.apiKeys.length > 0,
        status: "NO_WALLET",
        isReady: false,
        message: "User exists but no wallet. Call POST /api/bot/setup to create one."
      });
    }
    const balances = await walletService.getBalances(walletInfo.publicKey);
    const hasSol = balances.sol > 1e-3;
    const hasUsdc = balances.usdc > 0;
    let status;
    let isReady;
    if (!hasSol && !hasUsdc) {
      status = "NEEDS_FUNDING";
      isReady = false;
    } else if (!hasSol) {
      status = "NEEDS_SOL";
      isReady = false;
    } else if (!hasUsdc) {
      status = "NEEDS_USDC";
      isReady = true;
    } else {
      status = "READY";
      isReady = true;
    }
    res.json({
      externalId,
      walletAddress: walletInfo.publicKey,
      walletType: walletInfo.type,
      hasWallet: true,
      hasApiKey: user.apiKeys.length > 0,
      balances: {
        sol: balances.sol,
        usdc: balances.usdc
      },
      status,
      isReady,
      message: isReady ? "Wallet ready for trading" : `Wallet needs funding. Send assets to ${walletInfo.publicKey}`
    });
  } catch (error) {
    next(error);
  }
});
